import "./index-first.css";

function IndexFirst(){



    return(
        <div className="container">
            <div className="bienvenida">
                <h1>BURGUERS&CHIPS</h1>
                <p>Descubre BURGUERS&CHIPS, donde las hamburguesas son artesanales y las papas fritas irresistibles. En un ambiente moderno, se sirven hamburguesas con ingredientes frescos y de alta calidad. Las papas fritas, crujientes por fuera y suaves por dentro, complementan perfectamente. El servicio, excepcional y amable, garantiza una experiencia memorable. BURGUERS&CHIPS es un destino gastronómico esencial para los amantes de la buena comida. ¡Ven y descubre por qué es el favorito de la ciudad!</p>
            </div>
            <img src="Burguer-cuadrada.png" alt="Burguer"/>
        </div>
    );
};

export default IndexFirst;
